57|const DECLARATION_PATTERNS: SymbolPattern[] = [
58|  { regex: /(?:^|\n)\s*(?:async\s+)?function\s+(\w+)\s*\(/g,        kind: 'function' },
59|  { regex: /(?:^|\n)\s*(?:export\s+)?(?:abstract\s+)?class\s+(\w+)/g, kind: 'class' },
